// Auto-generated: NotoSans Vietnamese subset (Regular), base64 TTF.
// Reused from frontend/src/lib/fonts/notoSansVi.ts so server-side PDF export
// (pdfkit) can embed a Unicode font that renders Vietnamese diacritics.
// Stored as base64 in a .ts module so it survives the tsc→dist build (a raw
// .ttf under src/ would not be emitted to dist/).
export const NOTO_SANS_VI_B64 = '';
export const notoSansViBuffer = (): Buffer => Buffer.from(NOTO_SANS_VI_B64, 'base64');

// NotoSans BOLD, Vietnamese subset (OFL). Fetched from googlefonts/noto-fonts
// (hinted TTF) and subset with pyftsubset to Latin+Vietnamese ranges — real
// bold weight replacing the earlier faux-bold stroke technique.
export const NOTO_SANS_VI_BOLD_B64 = '';
export const notoSansViBoldBuffer = (): Buffer => Buffer.from(NOTO_SANS_VI_BOLD_B64, 'base64');
